{"success":true,"content":"     1	/**
     2	 * Instruction loop: queue + dispatch for the Shipyard graph.
     3	 *
     4	 * Processes one instruction at a time (sequential for MVP).
     5	 * Instructions arrive via REST or WebSocket.
     6	 */
     7	
     8	import { v4 as uuid } from 'uuid';
     9	import { createShipyardGraph } from '../graph/builder.js';
    10	import { ContextStore } from '../context/store.js';
    11	import type { ShipyardStateType, ContextEntry } from '../graph/state.js';
    12	
    13	// ---------------------------------------------------------------------------
    14	// Types
    15	// ---------------------------------------------------------------------------
    16	
    17	export interface QueuedInstruction {
    18	  id: string;
    19	  instruction: string;
    20	  contexts: ContextEntry[];
    21	  createdAt: number;
    22	}
    23	
    24	export interface RunResult {
    25	  runId: string;
    26	  phase: ShipyardStateType['phase'];
    27	  steps: ShipyardStateType['steps'];
    28	  fileEdits: ShipyardStateType['fileEdits'];
    29	  tokenUsage: ShipyardStateType['tokenUsage'];
    30	  traceUrl: ShipyardStateType['traceUrl'];
    31	  messages: ShipyardStateType['messages'];
    32	  error: ShipyardStateType['error'];
    33	  durationMs: number;
    34	}
    35	
    36	export type StateListener = (state: Partial<ShipyardStateType>) => void;
    37	
    38	// ---------------------------------------------------------------------------
    39	// Instruction loop
    40	// ---------------------------------------------------------------------------
    41	
    42	export class InstructionLoop {
    43	  private queue: QueuedInstruction[] = [];
    44	  private processing = false;
    45	  private currentRunId: string | null = null;
    46	  private abortController: AbortController | null = null;
    47	  private contextStore = new ContextStore();
    48	  private runs: Map<string, RunResult> = new Map();
    49	  private listeners: Set<StateListener> = new Set();
    50	
    51	  /** Add a state change listener (for WebSocket broadcasting). */
    52	  onStateChange(fn: StateListener): () => void {
    53	    this.listeners.add(fn);
    54	    return () => this.listeners.delete(fn);
    55	  }
    56	
    57	  private broadcast(state: Partial<ShipyardStateType>): void {
    58	    for (const fn of this.listeners) {
    59	      try {
    60	        fn(state);
    61	      } catch {
    62	        // Listener errors don't crash the loop
    63	      }
    64	    }
    65	  }
    66	
    67	  /** Submit an instruction to the queue. */
    68	  submit(instruction: string, contexts?: ContextEntry[]): string {
    69	    const id = uuid();
    70	    this.queue.push({
    71	      id,
    72	      instruction,
    73	      contexts: contexts ?? [],
    74	      createdAt: Date.now(),
    75	    });
    76	    void this.processNext();
    77	    return id;
    78	  }
    79	
    80	  /** Inject context mid-run. */
    81	  injectContext(entry: ContextEntry): void {
    82	    this.contextStore.add(entry);
    83	  }
    84	
    85	  /** Cancel current run. */
    86	  cancel(): boolean {
    87	    if (this.abortController) {
    88	      this.abortController.abort();
    89	      this.abortController = null;
    90	      this.processing = false;
    91	      return true;
    92	    }
    93	    return false;
    94	  }
    95	
    96	  /** Get run result by ID. */
    97	  getRun(id: string): RunResult | undefined {
    98	    return this.runs.get(id);
    99	  }
   100	
   101	  /** Get all run results. */
   102	  getAllRuns(): RunResult[] {
   103	    return Array.from(this.runs.values());
   104	  }
   105	
   106	  /** Get current queue status. */
   107	  getStatus(): {
   108	    processing: boolean;
   109	    currentRunId: string | null;
   110	    queueLength: number;
   111	  } {
   112	    return {
   113	      processing: this.processing,
   114	      currentRunId: this.currentRunId,
   115	      queueLength: this.queue.length,
   116	    };
   117	  }
   118	
   119	  /** Process next instruction in the queue. */
   120	  private async processNext(): Promise<void> {
   121	    if (this.processing || this.queue.length === 0) return;
   122	
   123	    this.processing = true;
   124	    const item = this.queue.shift()!;
   125	    this.currentRunId = item.id;
   126	    this.abortController = new AbortController();
   127	
   128	    // Add contexts from the instruction
   129	    for (const ctx of item.contexts) {
   130	      this.contextStore.add(ctx);
   131	    }
   132	
   133	    const startedAt = Date.now();
   134	
   135	    try {
   136	      const graph = createShipyardGraph();
   137	
   138	      const initialState: Partial<ShipyardStateType> = {
   139	        runId: item.id,
   140	        traceId: uuid(),
   141	        instruction: item.instruction,
   142	        phase: 'planning',
   143	        steps: [],
   144	        currentStepIndex: 0,
   145	        fileEdits: [],
   146	        toolCallHistory: [],
   147	        verificationResult: null,
   148	        reviewDecision: null,
   149	        reviewFeedback: null,
   150	        contexts: this.contextStore.getAll(),
   151	        messages: [],
   152	        error: null,
   153	        retryCount: 0,
   154	        maxRetries: 3,
   155	        tokenUsage: null,
   156	        traceUrl: null,
   157	        runStartedAt: startedAt,
   158	        workerResults: [],
   159	        modelHint: 'opus',
   160	      };
   161	
   162	      this.broadcast(initialState);
   163	
   164	      const result = await graph.invoke(initialState, {
   165	        configurable: { thread_id: item.id },
   166	      });
   167	
   168	      const finalState = result as ShipyardStateType;
   169	      const runResult: RunResult = {
   170	        runId: item.id,
   171	        phase: finalState.phase,
   172	        steps: finalState.steps,
   173	        fileEdits: finalState.fileEdits,
   174	        tokenUsage: finalState.tokenUsage,
   175	        traceUrl: finalState.traceUrl,
   176	        messages: finalState.messages,
   177	        error: finalState.error,
   178	        durationMs: Date.now() - startedAt,
   179	      };
   180	
   181	      this.runs.set(item.id, runResult);
   182	      this.broadcast(finalState);
   183	    } catch (err: unknown) {
   184	      const errorMsg = err instanceof Error ? err.message : String(err);
   185	      const runResult: RunResult = {
   186	        runId: item.id,
   187	        phase: 'error',
   188	        steps: [],
   189	        fileEdits: [],
   190	        tokenUsage: null,
   191	        traceUrl: null,
   192	        messages: [],
   193	        error: errorMsg,
   194	        durationMs: Date.now() - startedAt,
   195	      };
   196	      this.runs.set(item.id, runResult);
   197	      this.broadcast({ phase: 'error', error: errorMsg });
   198	    } finally {
   199	      this.processing = false;
   200	      this.currentRunId = null;
   201	      this.abortController = null;
   202	      // Process next in queue
   203	      void this.processNext();
   204	    }
   205	  }
   206	}
